const cadastroConcluido = true;

if (cadastroConcluido) {
  console.log('Bem-vindo à plataforma.');
}

const assinaturaAtiva = false;

if (assinaturaAtiva) {
  console.log('Acesso à aula liberado.');
} else {
  console.log('Acesso bloqueado.');
}

const percentualConclusao = 62;

if (percentualConclusao >= 80) {
  console.log('Estágio avançado.');
} else if (percentualConclusao >= 40) {
  console.log('Estágio intermediário.');
} else {
  console.log('Estágio inicial.');
}

const usuarioAutenticado = true;
const usuarioInstrutor = true;

if (usuarioAutenticado) {
  if (usuarioInstrutor) {
    console.log('Acesso ao painel do instrutor liberado.');
  } else {
    console.log('Acesso comum de aluno liberado.');
  }
} else {
  console.log('Usuário não autenticado.');
}

const aulaConcluida = true;
const statusAula = aulaConcluida ? 'Concluída' : 'Pendente';

console.log(statusAula);

const planoUsuario = 'premium';

switch (planoUsuario) {
  case 'gratuito':
    console.log('Acesso básico liberado.');
    break;
  case 'padrao':
    console.log('Acesso intermediário liberado.');
    break;
  case 'premium':
    console.log('Acesso total liberado.');
    break;
  default:
    console.log('Plano não reconhecido.');
}
